"""Executor Protocol — Mantis 표준 실행 인터페이스."""

from __future__ import annotations

import time
from dataclasses import dataclass, field
from typing import Any, AsyncIterator, Protocol, runtime_checkable

from mantis.context.conversation import ConversationContext
from mantis.middleware.base import Middleware, BaseMiddleware, RunContext
from mantis.tools.registry import ToolRegistry


@dataclass
class ExecutionEvent:
    """실행 중 발생하는 이벤트."""

    type: str           # thinking, tool_call, tool_result, blocked, done, error
    data: dict[str, Any] | str
    phase: str = ""
    timestamp: float = field(default_factory=time.time)


@dataclass
class ExecutionContext:
    """Executor 실행 중 모든 Phase가 공유하는 상태."""

    session_id: str
    run_ctx: RunContext
    model: Any  # LLMProvider
    registry: ToolRegistry
    conversation: ConversationContext
    middlewares: list[Middleware | BaseMiddleware]

    # 선택 Provider
    search: Any | None = None    # SearchProvider
    sandbox: Any | None = None   # SandboxProvider
    workflows: Any | None = None # WorkflowStore
    state: Any | None = None     # StateStore

    # 플로우 모드
    flow: Any | None = None  # FlowState — 있으면 플로우 모드

    # 가변
    final_text: str = ""
    pending_events: list[dict[str, Any]] = field(default_factory=list)
    iteration: int = 0

    @property
    def tools(self) -> list[dict]:
        """현재 시점의 도구 스키마."""
        return self.registry.to_openai_tools(session_id=self.session_id)

    def has(self, capability: str) -> bool:
        """특정 기능이 활성화되어 있는지."""
        return getattr(self, capability, None) is not None


@runtime_checkable
class Executor(Protocol):
    """Mantis 표준 실행 인터페이스.

    어떤 구현이든 이 인터페이스만 맞추면 Mantis 생태계에서 동작한다.
    """

    async def run(self, input: str, *, session_id: str | None = None) -> str:
        """입력 → 최종 텍스트 응답."""
        ...

    async def run_stream(
        self, input: str, *, session_id: str | None = None
    ) -> AsyncIterator[dict]:
        """입력 → 실행 이벤트 스트림."""
        ...
